function maxCountTarget(nums, key) {
    let count = new Map();
    let maxCount = 0;
    let maxTarget = -1;
    for (let i = 1; i < nums.length; ++i) {
        if (nums[i - 1] === key) {
            count.set(nums[i], (count.get(nums[i]) || 0) + 1);
            if (count.get(nums[i]) > maxCount) {
                maxCount = count.get(nums[i]);
                maxTarget = nums[i];
            }
        }
    }
    return maxTarget;
}
